177	// DocGraph is the resolver for the docGraph field.
178	func (r *queryResolver) DocGraph(ctx context.Context) (*DocGraph, error) {
179		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
180		if err != nil {
181			return nil, fmt.Errorf("building document graph: %w", err)
182		}
183	
184		docs := graph.AllNodesForOutput()
185		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
186		gqlDocs := make([]*Document, len(docs))
187		for i, d := range docs {
188			gqlDocs[i] = docToGQL(d)
189		}
190	
191		pathToIDJSON, err := json.Marshal(graph.PathToID)
192		if err != nil {
193			return nil, fmt.Errorf("serializing pathToId: %w", err)
194		}
195		dependentsJSON, err := json.Marshal(graph.Dependents)
196		if err != nil {
197			return nil, fmt.Errorf("serializing dependents: %w", err)
198		}
199	
200		warnings := graph.Warnings
201		if warnings == nil {
202			warnings = []string{}
203		}
204	
205		return &DocGraph{
206			RootDir:    graph.RootDir,
207			Documents:  gqlDocs,
208			PathToID:   string(pathToIDJSON),
209			Dependents: string(dependentsJSON),
210			Warnings:   warnings,
211			Issues:     issuesToGQL(graph.Issues),
212		}, nil
213	}
