329	// stageWorkerWithAttempt registers a worker with the server's WorkerManager
330	// in a state where Show(id) returns a record that points at attemptID.
331	func stageWorkerWithAttempt(t *testing.T, srv *Server, workerID, attemptID string) {
332		t.Helper()
333		if srv.workers == nil {
334			t.Fatal("server has nil workers")
335		}
336		srv.workers.mu.Lock()
337		defer srv.workers.mu.Unlock()
338		if srv.workers.workers == nil {
339			srv.workers.workers = map[string]*workerHandle{}
340		}
341		srv.workers.workers[workerID] = &workerHandle{
342			record: WorkerRecord{
343				ID: workerID,
344				LastAttempt: &LastAttemptInfo{
345					AttemptID: attemptID,
346				},
347			},
348		}
349	}
