351	func mcpFirstContentFields(t *testing.T, w *httptest.ResponseRecorder) (text string, truncated bool, originalBytes int) {
352		t.Helper()
353		var resp jsonRPCResponse
354		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
355			t.Fatalf("invalid JSON: %v", err)
356		}
357		if resp.Error != nil {
358			t.Fatalf("rpc error: %s", resp.Error.Message)
359		}
360		result, ok := resp.Result.(map[string]any)
361		if !ok {
362			t.Fatalf("expected result map, got %T", resp.Result)
363		}
364		contentAny, ok := result["content"].([]any)
365		if !ok || len(contentAny) == 0 {
366			t.Fatalf("expected content array, got %v", result["content"])
367		}
368		first, ok := contentAny[0].(map[string]any)
369		if !ok {
370			t.Fatalf("expected first content to be map")
371		}
372		text, _ = first["text"].(string)
373		truncated, _ = first["truncated"].(bool)
374		if ob, ok := first["original_bytes"].(float64); ok {
375			originalBytes = int(ob)
376		}
377		return
378	}
