387	// TestEvidencePrimitiveUsage is the static-analysis gate for FEAT-022 §10
388	// (Stage E1). It asserts that every mcpContent{Type:"text", ...}
389	// composite-literal construction in cli/internal/server/server.go
390	// either:
391	//
392	//   - is sourced from a Text field that originates from
393	//     evidence.ClampOutput in the immediately enclosing function, OR
394	//   - carries an //evidence:allow-unbounded line-comment annotation on
395	//     the literal itself.
396	//
397	// The package-level mcpText helper is the single mcpContent literal site
398	// in this file; every other caller must route through that helper. The
399	// test parses server.go, walks the AST, and rejects any unannotated
400	// non-helper literal so that future contributors cannot reintroduce
401	// unbounded text egress on the MCP surface.
402	func TestEvidencePrimitiveUsage(t *testing.T) {
403		fset := token.NewFileSet()
404		file, err := parser.ParseFile(fset, "server.go", nil, parser.ParseComments)
405		if err != nil {
406			t.Fatalf("parse server.go: %v", err)
407		}
408	
409		// Build a map from line number → comment text for line-comments so
410		// we can check the //evidence:allow-unbounded annotation that may
411		// sit on the line before the literal.
412		commentByLine := map[int]string{}
413		for _, cg := range file.Comments {
414			for _, c := range cg.List {
415				line := fset.Position(c.Slash).Line
416				commentByLine[line] = c.Text
417			}
418		}
419	
420		var problems []string
421		ast.Inspect(file, func(n ast.Node) bool {
422			cl, ok := n.(*ast.CompositeLit)
423			if !ok {
424				return true
425			}
426			ident, ok := cl.Type.(*ast.Ident)
427			if !ok || ident.Name != "mcpContent" {
428				return true
429			}
430			// Only consider literals whose Type field is "text".
431			hasTextType := false
432			for _, elt := range cl.Elts {
433				kv, ok := elt.(*ast.KeyValueExpr)
434				if !ok {
435					continue
436				}
437				key, ok := kv.Key.(*ast.Ident)
438				if !ok || key.Name != "Type" {
439					continue
440				}
441				if bl, ok := kv.Value.(*ast.BasicLit); ok && bl.Value == `"text"` {
442					hasTextType = true
443				}
444			}
445			if !hasTextType {
446				return true
447			}
448			// Allow when the line immediately before the literal carries
449			// the annotation comment.
450			startLine := fset.Position(cl.Lbrace).Line
451			annotated := false
452			for delta := 1; delta <= 3; delta++ {
453				if c, ok := commentByLine[startLine-delta]; ok {
454					if strings.Contains(c, "evidence:allow-unbounded") && strings.Contains(c, `reason="`) {
455						annotated = true
456						break
457					}
458				}
459			}
460			if !annotated {
461				problems = append(problems, fset.Position(cl.Lbrace).String())
462			}
463			return true
464		})
465	
466		if len(problems) > 0 {
467			t.Fatalf("found unannotated mcpContent{Type:\"text\"} literal sites in server.go (each must use evidence.ClampOutput via the mcpText helper, or carry //evidence:allow-unbounded). Sites:\n  %s",
468				strings.Join(problems, "\n  "))
469		}
470	}
