54	func (m *Plugin) generateSingleFile(data *codegen.Data) error {
55		file := File{}
56	
57		if fileExists(data.Config.Resolver.Filename) &&
58			data.Config.Resolver.PreserveResolver {
59			// file already exists and config says not to update resolver
60			// so just return
61			return nil
62		}
63	
64		rewriter, err := rewrite.New(data.Config.Resolver.Dir())
65		if err != nil {
66			return err
67		}
68	
69		for _, o := range data.Objects {
70			if o.HasResolvers() {
71				caser := cases.Title(language.English, cases.NoLower)
72				rewriter.MarkStructCopied(
73					templates.LcFirst(o.Name) + templates.UcFirst(data.Config.Resolver.Type),
74				)
75				rewriter.GetMethodBody(data.Config.Resolver.Type, caser.String(o.Name))
76	
77				file.Objects = append(file.Objects, o)
78			}
79	
80			for _, f := range o.Fields {
81				if !f.IsResolver {
82					continue
83				}
84	
85				structName := templates.LcFirst(o.Name) + templates.UcFirst(data.Config.Resolver.Type)
86				comment := strings.TrimSpace(
87					strings.TrimLeft(rewriter.GetMethodComment(structName, f.GoFieldName), `\`),
88				)
89				implementation := strings.TrimSpace(rewriter.GetMethodBody(structName, f.GoFieldName))
90				if implementation != "" {
91					resolver := Resolver{
92						o,
93						f,
94						rewriter.GetPrevDecl(structName, f.GoFieldName),
95						comment,
96						implementation,
97						nil,
98					}
99					file.Resolvers = append(file.Resolvers, &resolver)
100				} else {
101					resolver := Resolver{o, f, nil, "", `panic("not implemented")`, nil}
102					file.Resolvers = append(file.Resolvers, &resolver)
103				}
104			}
105		}
106	
107		if fileExists(data.Config.Resolver.Filename) {
108			file.name = data.Config.Resolver.Filename
109			file.imports = rewriter.ExistingImports(file.name)
110			file.RemainingSource = rewriter.RemainingSource(file.name)
111		}
112	
113		resolverBuild := &ResolverBuild{
114			File:                &file,
115			PackageName:         data.Config.Resolver.Package,
116			ResolverType:        data.Config.Resolver.Type,
117			HasRoot:             true,
118			OmitTemplateComment: data.Config.Resolver.OmitTemplateComment,
119		}
